import { z } from "zod";

export const webhookDeliverRequestSchema = z.object({
  url: z.string().url().max(2048),
  event: z.string().min(1).max(100),
  payload: z.unknown(),
  secret: z.string().min(16).max(256).optional(),
  retry_policy: z
    .object({
      max_retries: z.number().int().min(0).max(5).optional().default(3),
      backoff_seconds: z.number().int().min(1).max(300).optional().default(5),
    })
    .optional(),
  idempotency_key: z.string().max(128).optional(),
});

export const webhookDeliverResponseSchema = z.object({
  delivery_id: z.string(),
  status: z.enum(["delivered", "pending", "failed"]),
  status_code: z.number().nullable(),
  attempts: z.number(),
  next_retry_at: z.string().nullable(),
});

export type WebhookDeliverRequest = z.infer<
  typeof webhookDeliverRequestSchema
>;
export type WebhookDeliverResponse = z.infer<
  typeof webhookDeliverResponseSchema
>;
